SELECT u.id,u.display_name,u.reputation,COUNT(p.id) AS post_count,SUM(CASE WHEN p.post_type_id=1 THEN 1 ELSE 0 END) AS question_count,SUM(CASE WHEN p.post_type_id=2 THEN 1 ELSE 0 END) AS answer_count,COALESCE(SUM(p.score),0) AS total_score FROM users u LEFT JOIN posts p ON p.owner_user_id=u.id WHERE u.id=496624 GROUP BY u.id,u.display_name,u.reputation;
SELECT u.id,u.display_name,COUNT(c.id) AS comment_count,COUNT(DISTINCT c.post_id) AS commented_posts,COALESCE(SUM(c.score),0) AS comment_score FROM users u LEFT JOIN comments c ON c.user_id=u.id WHERE u.id=246511 GROUP BY u.id,u.display_name;
SELECT u.id,u.display_name,b.class,COUNT(b.id) AS badge_count,MIN(b.badge_date) AS first_badge,MAX(b.badge_date) AS last_badge FROM users u LEFT JOIN badges b ON b.user_id=u.id WHERE u.id=5123459 GROUP BY u.id,u.display_name,b.class ORDER BY b.class;
SELECT u.id,u.display_name,COUNT(ph.id) AS revision_count,COUNT(DISTINCT ph.post_id) AS edited_posts,COUNT(DISTINCT ph.post_history_type_id) AS history_type_count,MAX(ph.creation_date) AS last_revision FROM users u LEFT JOIN post_history ph ON ph.user_id=u.id WHERE u.id=8000123 GROUP BY u.id,u.display_name;
WITH owned_stats AS (SELECT owner_user_id,COUNT(*) AS owned_posts,SUM(score) AS owned_score FROM posts WHERE owner_user_id=9800001 GROUP BY owner_user_id),edited_stats AS (SELECT last_editor_user_id,COUNT(*) AS last_edited_posts FROM posts WHERE last_editor_user_id=9800001 GROUP BY last_editor_user_id) SELECT u.id,u.display_name,COALESCE(os.owned_posts,0) AS owned_posts,COALESCE(es.last_edited_posts,0) AS last_edited_posts,COALESCE(os.owned_score,0) AS owned_score FROM users u LEFT JOIN owned_stats os ON os.owner_user_id=u.id LEFT JOIN edited_stats es ON es.last_editor_user_id=u.id WHERE u.id=9800001;
SELECT u.id,u.display_name,u.reputation,COUNT(p.id) AS post_count,COALESCE(SUM(p.score),0) AS total_score FROM users u LEFT JOIN posts p ON p.owner_user_id=u.id WHERE u.id IN (232136,232756,234152,238100) GROUP BY u.id,u.display_name,u.reputation ORDER BY u.id;
SELECT u.id,u.display_name,u.reputation,COUNT(p.id) AS post_count,COALESCE(SUM(p.score),0) AS total_score FROM users u LEFT JOIN posts p ON p.owner_user_id=u.id WHERE u.id IN (100001,1500002,5100003,9000004) GROUP BY u.id,u.display_name,u.reputation ORDER BY u.id;
SELECT u.id,u.display_name,COUNT(c.id) AS comment_count,COUNT(DISTINCT c.post_id) AS commented_posts FROM users u LEFT JOIN comments c ON c.user_id=u.id WHERE u.id IN (57100,57240,58876,59608) GROUP BY u.id,u.display_name ORDER BY comment_count DESC,u.id;
WITH selected_users AS (SELECT id,display_name,reputation FROM users WHERE id IN (232136,232756,234152,238100)),post_stats AS (SELECT p.owner_user_id,COUNT(*) AS post_count,SUM(p.score) AS total_score,AVG(p.view_count) AS avg_views FROM posts p JOIN selected_users su ON su.id=p.owner_user_id WHERE p.creation_date>='2009-01-01' AND p.creation_date<'2010-01-01' GROUP BY p.owner_user_id) SELECT su.id,su.display_name,su.reputation,COALESCE(ps.post_count,0) AS post_count,COALESCE(ps.total_score,0) AS total_score,ps.avg_views FROM selected_users su LEFT JOIN post_stats ps ON ps.owner_user_id=su.id ORDER BY total_score DESC;
SELECT u.id,u.display_name,u.reputation,COUNT(p.id) AS post_count,COALESCE(SUM(p.score),0) AS total_score FROM users u LEFT JOIN posts p ON p.owner_user_id=u.id WHERE u.id>=5000000 AND u.id<5100000 GROUP BY u.id,u.display_name,u.reputation ORDER BY total_score DESC LIMIT 100;
SELECT u.id,u.display_name,u.reputation,COUNT(p.id) AS post_count,AVG(p.score) AS avg_post_score,COALESCE(SUM(p.view_count),0) AS total_views FROM users u LEFT JOIN posts p ON p.owner_user_id=u.id WHERE u.reputation>=10000 GROUP BY u.id,u.display_name,u.reputation ORDER BY u.reputation DESC LIMIT 100;
SELECT u.id,u.display_name,u.creation_date,COUNT(p.id) AS post_count,COALESCE(SUM(p.score),0) AS total_score FROM users u LEFT JOIN posts p ON p.owner_user_id=u.id WHERE u.creation_date>='2009-01-01' AND u.creation_date<'2010-01-01' GROUP BY u.id,u.display_name,u.creation_date ORDER BY total_score DESC LIMIT 100;
SELECT u.id,u.display_name,u.reputation,COUNT(p.id) AS question_count,COALESCE(SUM(p.score),0) AS total_score,AVG(p.view_count) AS avg_views FROM posts p JOIN users u ON u.id=p.owner_user_id WHERE p.creation_date>='2009-04-01' AND p.creation_date<'2009-07-01' AND p.post_type_id=1 GROUP BY u.id,u.display_name,u.reputation HAVING COUNT(p.id)>=3 ORDER BY total_score DESC LIMIT 100;
SELECT u.id,u.display_name,u.reputation,COUNT(p.id) AS answer_count,COALESCE(SUM(p.score),0) AS total_answer_score,AVG(p.score) AS avg_answer_score FROM posts p JOIN users u ON u.id=p.owner_user_id WHERE p.creation_date>='2009-04-01' AND p.creation_date<'2009-07-01' AND p.post_type_id=2 GROUP BY u.id,u.display_name,u.reputation HAVING COUNT(p.id)>=3 ORDER BY total_answer_score DESC LIMIT 100;
SELECT u.id,u.display_name,COUNT(c.id) AS comment_count,COUNT(DISTINCT p.id) AS commented_questions,COALESCE(SUM(c.score),0) AS total_comment_score FROM posts p JOIN comments c ON c.post_id=p.id JOIN users u ON u.id=c.user_id WHERE p.creation_date>='2009-04-01' AND p.creation_date<'2009-07-01' AND p.post_type_id=1 GROUP BY u.id,u.display_name ORDER BY comment_count DESC LIMIT 100;
SELECT q.id AS question_id,q.post_title,qu.id AS question_author_id,qu.display_name AS question_author,a.id AS answer_id,au.id AS answer_author_id,au.display_name AS answer_author,a.score AS answer_score FROM posts q JOIN posts a ON a.id=q.accepted_answer_id LEFT JOIN users qu ON qu.id=q.owner_user_id LEFT JOIN users au ON au.id=a.owner_user_id WHERE au.id=49 AND q.creation_date>='2009-01-01' AND q.creation_date<'2010-01-01' ORDER BY a.score DESC LIMIT 100;
SELECT q.id AS question_id,q.post_title,qu.id AS question_author_id,qu.display_name AS question_author,a.id AS answer_id,au.id AS answer_author_id,au.display_name AS answer_author FROM posts q JOIN posts a ON a.parent_id=q.id JOIN users qu ON qu.id=q.owner_user_id JOIN users au ON au.id=a.owner_user_id WHERE qu.id IN (2417600,5562701,2315276,1604377,3452342) AND au.id IN (4363956,2976522,6977241,1733235,3319513) AND q.creation_date>='2009-04-01' AND q.creation_date<'2009-07-01' LIMIT 100;
WITH selected_users AS (SELECT id,display_name,reputation FROM users WHERE id IN (100001,650001,1500001,3200001,5100001,7000001,8500001,9800001)),post_stats AS (SELECT p.owner_user_id,COUNT(*) AS post_count,SUM(p.score) AS total_score,AVG(p.view_count) AS avg_views FROM posts p JOIN selected_users su ON su.id=p.owner_user_id WHERE p.creation_date>='2009-01-01' AND p.creation_date<'2010-01-01' GROUP BY p.owner_user_id) SELECT su.id,su.display_name,su.reputation,COALESCE(ps.post_count,0) AS post_count,COALESCE(ps.total_score,0) AS total_score,ps.avg_views FROM selected_users su LEFT JOIN post_stats ps ON ps.owner_user_id=su.id ORDER BY total_score DESC;
WITH selected_users AS (SELECT id,display_name,reputation FROM users WHERE id IN (100001,650002,1500003,3200004,5100005,7000006,8500007,9800008)),post_stats AS (SELECT p.owner_user_id,COUNT(*) AS post_count,SUM(p.score) AS total_score FROM posts p JOIN selected_users su ON su.id=p.owner_user_id GROUP BY p.owner_user_id),comment_stats AS (SELECT c.user_id,COUNT(*) AS comment_count,SUM(c.score) AS comment_score FROM comments c JOIN selected_users su ON su.id=c.user_id GROUP BY c.user_id) SELECT su.id,su.display_name,su.reputation,COALESCE(ps.post_count,0) AS post_count,COALESCE(ps.total_score,0) AS total_score,COALESCE(cs.comment_count,0) AS comment_count,COALESCE(cs.comment_score,0) AS comment_score FROM selected_users su LEFT JOIN post_stats ps ON ps.owner_user_id=su.id LEFT JOIN comment_stats cs ON cs.user_id=su.id ORDER BY total_score DESC,comment_count DESC;
WITH user_activity AS (SELECT u.id,u.display_name,u.reputation,COUNT(p.id) AS post_count,COALESCE(SUM(p.score),0) AS total_score FROM users u LEFT JOIN posts p ON p.owner_user_id=u.id WHERE u.reputation>=1000 GROUP BY u.id,u.display_name,u.reputation) SELECT id,display_name,reputation,post_count,total_score,DENSE_RANK() OVER (ORDER BY total_score DESC) AS score_rank,DENSE_RANK() OVER (ORDER BY post_count DESC) AS activity_rank FROM user_activity ORDER BY score_rank LIMIT 100;